var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-01: <color=#ffd34c>【부록-001】 관계자 증언</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. FS007M0000-01：<color=#ffd34c>【付録-001】関係者証言</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-01: <color=#ffd34c>【Appendix-001】 Contact Testimony</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-01: <color=#ffd34c>【附錄-001】 相關人士證言</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"미나요?","JPN":"ミナですか？","ENG":"Mina?","TWN":"你說米娜？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그야 당연히 알죠. 우리 중학교에서 걔 모르는 애 없었을걸요.","JPN":"もちろん知ってます。うちの中学では、あの子を知らない人はいないと思います。","ENG":"Of course I know her. Everyone in my middle school probably knew about her.","TWN":"我當然認識她啊，我們中學幾乎沒有人不認識她的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"啊？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"혹시 동명이인 아니에요?","JPN":"ただの同姓同名とかじゃないんですか？","ENG":"Are we talking about the same person?","TWN":"不會是同名的兩個人吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"미나 걔는......","JPN":"ミナは……","ENG":"Mina was...","TWN":"米娜……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"말수가 적기는 해도 다른 사람 이야기를 잘 들어 주는 성격이었어요. ","JPN":"口数は少ないけど、人の話をちゃんと聞いてくれる子でした。","ENG":"She was a bit shy, but she was really a good listener. ","TWN":"她話雖然很少，但個性很擅長傾聽別人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"왜, 그런 타입 있잖아요.","JPN":"ほら、そういうタイプいるじゃないですか。","ENG":"You know, the kind of person","TWN":"在我們身邊不也經常看到這種類型的朋友嗎。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"옆에 가만히 있는데 이런저런 이야기가 술술 나오는 타입.","JPN":"隣に黙っていてくれてるだけなのに、色んな話をしたくなる人。","ENG":"you can keep on talking to even if she's just sitting by your side.","TWN":"只是靜靜坐在你旁邊，你卻會自然地想跟她談天說地，她就是那種類型。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그리고....... 뭐랄까......","JPN":"それから……う～ん……","ENG":"And... she was...","TWN":"然後……怎麼說呢……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"역시 좀 얌전한 편이었어요. 미나 걔.","JPN":"ミナは、おとなしい方ではありましたね。","ENG":"She was definitely a modest girl. Mina, I mean.","TWN":"米娜應該算是比較文靜的女孩。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"중학생 때는 다들 왁자지껄하게 놀잖아요?","JPN":"中学の時って結構騒いだり、やんちゃしたりするじゃないですか？","ENG":"You know how typical teenagers are always loud and full of energy?","TWN":"國中的時候，大家都是吵吵鬧鬧的嘛。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 미나는 안 그랬어요.","JPN":"でもミナはそんな感じじゃありませんでした。","ENG":"But that wasn't the case for Mina.","TWN":"但米娜卻沒有那樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"다른 사람이 안 찾으면 혼자 조용히 앉아 있었거든요.","JPN":"誰かが話しかけないと、一人で黙って席に座ってるタイプ？","ENG":"She would always sit quietly unless someone talked to her first.","TWN":"沒人找她的時候，她都是一個人安靜地坐在位子上。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"다른 애들보다 확실히 차분했어요.","JPN":"他の子より確かに静かではありましたね。","ENG":"She was certainly a lot calmer than the others.","TWN":"跟其他同學相比，她確實是比較穩重。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......제 기억으로는요.","JPN":"……あくまでも私の記憶ですが。","ENG":"At least in my memory.","TWN":"……在我的記憶中是這樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래서 오히려 남자애들에게 은근 인기 많았죠.","JPN":"あっ、男の子たちに結構人気ありましたよ。","ENG":"That's why Mina was quite popular amongst the boys.","TWN":"所以她在男生中的人氣很高。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"연상 같은 느낌이라나 뭐라나......","JPN":"年上みたいな魅力があるというか……","ENG":"They said she was more mature than other girls.","TWN":"據說是有種年長的感覺……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"제가 중학생 때 고백했던 선배도 그런 말 같지도 않은 소리를 하면서 거절했다니까요.","JPN":"私が中学の時に告白した先輩からも、そんなバカみたいな理由でフラれました。","ENG":"One of the boys I asked out back in middle school rejected me by saying something like that.","TWN":"我國中時曾經告白過的學長，也是用這種荒唐的理由拒絕了我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하아......","JPN":"はぁ……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"생각하니까 또 열받네.......","JPN":"思い出したら、イライラしてきた……","ENG":"Just thinking about it makes me angry all over again.","TWN":"想起來就有點生氣……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"뭐, 어쨌거나 학교에서는 유명인이었어요.","JPN":"とにかく、学校では有名でしたね。","ENG":"Anyway, Mina was really famous back in school.","TWN":"反正她在我們學校是個名人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"집안 사정은 저도 잘 모르지만.......","JPN":"家庭の事情とかは、よく知りませんが……","ENG":"I don't know much about her family...","TWN":"雖然我不太清楚她家裡的情況……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"엄청 잘 사는 집안 딸이란 소문도 돌았고요.","JPN":"大金持ちの令嬢っていう噂が流れた時もありましたし。","ENG":"But there was a rumor she came from a well-off family.","TWN":"傳聞中說她是個千金大小姐呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 그치.","JPN":"あっ、そうそう。","ENG":"Oh, right.","TWN":"啊，對了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"걔네 언니가 진짜 예뻤어요.","JPN":"あの子のお姉さんが、すごく美人でした。","ENG":"Her sister was really pretty.","TWN":"她的姐姐很漂亮喔。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"한 번은 진로 상담 기간이라 학교에 온 적이 있었거든요?","JPN":"一度、進路相談の三者面談でお姉さんが学校に来たことがあって。","ENG":"She came to school once on Mina's career counseling day.","TWN":"在學校諮詢未來出路的期間，她姐姐曾經來過我們學校一次呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"와, 미나 걔가 누굴 닮았나 했는데 언니 쪽은 더하더라니까요.","JPN":"ミナも綺麗だけど、お姉さんの方はもっと綺麗でしたね。","ENG":"Wow, I always wondered who Mina took after, but her sister was on another level.","TWN":"哇，我們還在想米娜到底是像誰，結果她姐姐比她更漂亮呢"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......요즘에요?","JPN":"……最近ですか？","ENG":"Recently?","TWN":"……最近嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아뇨, 중학교 졸업하고 나선 한 번도 못 봤어요.","JPN":"いえ、中学を卒業してからは一度も会ってません。","ENG":"No, I haven't seen her since we graduated.","TWN":"沒有，國中畢業後，我就沒有見過她了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"으음......","JPN":"う～ん……","ENG":"Um...","TWN":"嗯……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"걔랑 연락하고 지낼 만한 애가 한 명 있긴 한데......","JPN":"あの子と連絡を取ってそうな子は一人いるけど……","ENG":"There is another girl who could still be in contact with her...","TWN":"可能有個人和她有一直保持著連絡……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"이름이......","JPN":"確か名前が……","ENG":"Her name was...","TWN":"她好像叫……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"나래였나......?","JPN":"ナルミだったかな……？","ENG":"Narae, I think?","TWN":"娜拉……?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};